  <script>
    (() => {
      const SIZE = 9;
      const EMPTY = 0;
      const BLACK = 1;
      const WHITE = 2;
      const KOMI = 6.5;
      const COLUMN_LABELS = ["A", "B", "C", "D", "E", "F", "G", "H", "J"];
      const STAR_POINTS = [
        [2, 2], [2, 6],
        [4, 4],
        [6, 2], [6, 6],
      ];

      const canvas = document.getElementById("board");
      const ctx = canvas.getContext("2d");
      const boardWrap = document.querySelector(".board-wrap");

      const turnPill = document.getElementById("turnPill");
      const moveCount = document.getElementById("moveCount");
      const passCount = document.getElementById("passCount");
      const blackCaptures = document.getElementById("blackCaptures");
      const whiteCaptures = document.getElementById("whiteCaptures");
      const message = document.getElementById("message");
      const blackScore = document.getElementById("blackScore");
      const whiteScore = document.getElementById("whiteScore");
      const blackBreakdown = document.getElementById("blackBreakdown");
      const whiteBreakdown = document.getElementById("whiteBreakdown");
      const scoreSummary = document.getElementById("scoreSummary");
      const passBtn = document.getElementById("passBtn");
      const undoBtn = document.getElementById("undoBtn");
      const newBtn = document.getElementById("newBtn");

      const state = {};
      let history = [];
      let hoverPoint = null;
      let metrics = null;

      function createBoard() {
        return Array.from({ length: SIZE }, () => Array(SIZE).fill(EMPTY));
      }

      function cloneBoard(board) {
        return board.map((row) => row.slice());
      }

      function cloneCaptures(captures) {
        return {
          [BLACK]: captures[BLACK],
          [WHITE]: captures[WHITE],
        };
      }

      function otherPlayer(player) {
        return player === BLACK ? WHITE : BLACK;
      }

      function playerName(player) {
        return player === BLACK ? "Black" : "White";
      }

      function formatPoints(value) {
        return Number.isInteger(value) ? String(value) : value.toFixed(1);
      }

      function boardSignature(board) {
        return board.map((row) => row.join("")).join("|");
      }

      function coordName(row, col) {
        return `${COLUMN_LABELS[col]}${SIZE - row}`;
      }

      function snapshotState() {
        return {
          board: cloneBoard(state.board),
          currentPlayer: state.currentPlayer,
          captures: cloneCaptures(state.captures),
          passes: state.passes,
          moveNumber: state.moveNumber,
          gameOver: state.gameOver,
          lastMove: state.lastMove ? { ...state.lastMove } : null,
          lastAction: state.lastAction ? { ...state.lastAction } : null,
          note: state.note,
          signature: boardSignature(state.board),
        };
      }

      function restoreSnapshot(snapshot) {
        state.board = cloneBoard(snapshot.board);
        state.currentPlayer = snapshot.currentPlayer;
        state.captures = cloneCaptures(snapshot.captures);
        state.passes = snapshot.passes;
        state.moveNumber = snapshot.moveNumber;
        state.gameOver = snapshot.gameOver;
        state.lastMove = snapshot.lastMove ? { ...snapshot.lastMove } : null;
        state.lastAction = snapshot.lastAction ? { ...snapshot.lastAction } : null;
        state.note = snapshot.note;
      }

      function resetGame() {
        state.board = createBoard();
        state.currentPlayer = BLACK;
        state.captures = { [BLACK]: 0, [WHITE]: 0 };
        state.passes = 0;
        state.moveNumber = 0;
        state.gameOver = false;
        state.lastMove = null;
        state.lastAction = null;
        state.note = "Black to play. Click any intersection to place a stone.";
        history = [snapshotState()];
        hoverPoint = null;
        resizeCanvas();
      }

      function pushHistory() {
        history.push(snapshotState());
      }

      function getNeighbors(row, col) {
        const neighbors = [];
        if (row > 0) neighbors.push([row - 1, col]);
        if (row < SIZE - 1) neighbors.push([row + 1, col]);
        if (col > 0) neighbors.push([row, col - 1]);
        if (col < SIZE - 1) neighbors.push([row, col + 1]);
        return neighbors;
      }

      function collectGroup(board, startRow, startCol) {
        const color = board[startRow][startCol];
        const stack = [[startRow, startCol]];
        const visited = new Set([`${startRow},${startCol}`]);
        const liberties = new Set();
        const stones = [];

        while (stack.length > 0) {
          const [row, col] = stack.pop();
          stones.push([row, col]);

          for (const [nextRow, nextCol] of getNeighbors(row, col)) {
            const value = board[nextRow][nextCol];
            if (value === EMPTY) {
              liberties.add(`${nextRow},${nextCol}`);
              continue;
            }

            if (value !== color) {
              continue;
            }

            const key = `${nextRow},${nextCol}`;
            if (!visited.has(key)) {
              visited.add(key);
              stack.push([nextRow, nextCol]);
            }
          }
        }

        return { color, stones, liberties };
      }

      function removeGroup(board, group) {
        for (const [row, col] of group.stones) {
          board[row][col] = EMPTY;
        }
      }

      function computeAreaScore(board) {
        const seen = Array.from({ length: SIZE }, () => Array(SIZE).fill(false));
        let blackStones = 0;
        let whiteStones = 0;
        let blackTerritory = 0;
        let whiteTerritory = 0;
        let neutralPoints = 0;

        for (let row = 0; row < SIZE; row += 1) {
          for (let col = 0; col < SIZE; col += 1) {
            if (board[row][col] === BLACK) {
              blackStones += 1;
              continue;
            }
            if (board[row][col] === WHITE) {
              whiteStones += 1;
              continue;
            }
            if (seen[row][col]) {
              continue;
            }

            const stack = [[row, col]];
            const region = [];
            const bordering = new Set();
            seen[row][col] = true;

            while (stack.length > 0) {
              const [currentRow, currentCol] = stack.pop();
              region.push([currentRow, currentCol]);

              for (const [nextRow, nextCol] of getNeighbors(currentRow, currentCol)) {
                const value = board[nextRow][nextCol];
                if (value === EMPTY) {
                  if (!seen[nextRow][nextCol]) {
                    seen[nextRow][nextCol] = true;
                    stack.push([nextRow, nextCol]);
                  }
                } else {
                  bordering.add(value);
                }
              }
            }

            if (bordering.size === 1) {
              const owner = bordering.has(BLACK) ? BLACK : WHITE;
              if (owner === BLACK) {
                blackTerritory += region.length;
              } else {
                whiteTerritory += region.length;
              }
            } else {
              neutralPoints += region.length;
            }
          }
        }

        const blackTotal = blackStones + blackTerritory;
        const whiteTotal = whiteStones + whiteTerritory + KOMI;
        const margin = Math.abs(blackTotal - whiteTotal);
        const winner = blackTotal === whiteTotal ? "Tie" : (blackTotal > whiteTotal ? "Black" : "White");

        return {
          blackStones,
          whiteStones,
          blackTerritory,
          whiteTerritory,
          neutralPoints,
          blackTotal,
          whiteTotal,
          winner,
          margin,
        };
      }

      function attemptPlay(row, col) {
        if (state.gameOver) {
          state.note = "The game is over. Start a new game or undo to keep playing.";
          render();
          return false;
        }

        if (state.board[row][col] !== EMPTY) {
          state.note = `${coordName(row, col)} is already occupied.`;
          render();
          return false;
        }

        const player = state.currentPlayer;
        const opponent = otherPlayer(player);
        const nextBoard = cloneBoard(state.board);
        nextBoard[row][col] = player;

        let capturedCount = 0;
        const checked = new Set();

        for (const [nextRow, nextCol] of getNeighbors(row, col)) {
          if (nextBoard[nextRow][nextCol] !== opponent) {
            continue;
          }

          const key = `${nextRow},${nextCol}`;
          if (checked.has(key)) {
            continue;
          }

          const group = collectGroup(nextBoard, nextRow, nextCol);
          for (const [groupRow, groupCol] of group.stones) {
            checked.add(`${groupRow},${groupCol}`);
          }

          if (group.liberties.size === 0) {
            capturedCount += group.stones.length;
            removeGroup(nextBoard, group);
          }
        }

        const ownGroup = collectGroup(nextBoard, row, col);
        if (ownGroup.liberties.size === 0) {
          state.note = "Illegal move: suicide is not allowed.";
          render();
          return false;
        }

        const nextSignature = boardSignature(nextBoard);
        if (history.some((entry) => entry.signature === nextSignature)) {
          state.note = "Illegal move: board repetition is not allowed here (ko / superko).";
          render();
          return false;
        }

        state.board = nextBoard;
        state.captures[player] += capturedCount;
        state.currentPlayer = opponent;
        state.passes = 0;
        state.moveNumber += 1;
        state.gameOver = false;
        state.lastMove = { row, col, player };
        state.lastAction = { type: "move", row, col, player, capturedCount };
        state.note = capturedCount > 0
          ? `${playerName(player)} played ${coordName(row, col)} and captured ${capturedCount} ${capturedCount === 1 ? "stone" : "stones"}.`
          : `${playerName(player)} played ${coordName(row, col)}.`;

        pushHistory();
        render();
        return true;
      }

      function passTurn() {
        if (state.gameOver) {
          state.note = "The game is already over. Start a new game or undo to continue.";
          render();
          return false;
        }

        const player = state.currentPlayer;
        state.moveNumber += 1;
        state.passes += 1;
        state.lastMove = null;
        state.lastAction = { type: "pass", player };
        state.currentPlayer = otherPlayer(player);

        if (state.passes >= 2) {
          state.gameOver = true;
          const score = computeAreaScore(state.board);
          if (score.winner === "Tie") {
            state.note = "Both players passed. Game over — the area estimate is a tie.";
          } else {
            state.note = `Both players passed. Game over — ${score.winner} wins by ${formatPoints(score.margin)} on the area estimate.`;
          }
        } else {
          state.note = `${playerName(player)} passed.`;
        }

        pushHistory();
        render();
        return true;
      }

      function undoMove() {
        if (history.length <= 1) {
          state.note = "Nothing to undo.";
          render();
          return false;
        }

        history.pop();
        restoreSnapshot(history[history.length - 1]);
        state.note = "Undid the last action.";
        render();
        return true;
      }

      function updateStatus() {
        moveCount.textContent = state.moveNumber;
        passCount.textContent = state.passes;
        blackCaptures.textContent = state.captures[BLACK];
        whiteCaptures.textContent = state.captures[WHITE];
        message.textContent = state.note;

        if (state.gameOver) {
          turnPill.className = "turn-pill gameover";
          turnPill.textContent = "Game over";
        } else {
          const className = state.currentPlayer === BLACK ? "black" : "white";
          turnPill.className = `turn-pill ${className}`;
          turnPill.textContent = `${playerName(state.currentPlayer)} to play`;
        }

        const score = computeAreaScore(state.board);
        blackScore.textContent = formatPoints(score.blackTotal);
        whiteScore.textContent = formatPoints(score.whiteTotal);
        blackBreakdown.textContent = `${score.blackStones} stones + ${score.blackTerritory} territory`;
        whiteBreakdown.textContent = `${score.whiteStones} stones + ${score.whiteTerritory} territory + ${formatPoints(KOMI)} komi`;

        if (score.winner === "Tie") {
          scoreSummary.textContent = state.gameOver
            ? "Final area estimate: tie game."
            : "Current area estimate: tie game.";
        } else {
          scoreSummary.textContent = `${state.gameOver ? "Final" : "Current"} area estimate: ${score.winner} leads by ${formatPoints(score.margin)}.`;
        }
      }

      function drawRoundedRect(x, y, width, height, radius) {
        ctx.beginPath();
        ctx.moveTo(x + radius, y);
        ctx.lineTo(x + width - radius, y);
        ctx.quadraticCurveTo(x + width, y, x + width, y + radius);
        ctx.lineTo(x + width, y + height - radius);
        ctx.quadraticCurveTo(x + width, y + height, x + width - radius, y + height);
        ctx.lineTo(x + radius, y + height);
        ctx.quadraticCurveTo(x, y + height, x, y + height - radius);
        ctx.lineTo(x, y + radius);
        ctx.quadraticCurveTo(x, y, x + radius, y);
        ctx.closePath();
      }

      function drawStone(x, y, radius, player, alpha = 1, lastMove = false) {
        ctx.save();
        ctx.globalAlpha = alpha;
        ctx.shadowColor = player === BLACK ? "rgba(0, 0, 0, 0.34)" : "rgba(0, 0, 0, 0.18)";
        ctx.shadowBlur = radius * 0.45;
        ctx.shadowOffsetY = radius * 0.16;

        const gradient = ctx.createRadialGradient(
          x - radius * 0.34,
          y - radius * 0.38,
          radius * 0.12,
          x,
          y,
          radius
        );

        if (player === BLACK) {
          gradient.addColorStop(0, "#6b7280");
          gradient.addColorStop(0.35, "#27272a");
          gradient.addColorStop(1, "#020617");
        } else {
          gradient.addColorStop(0, "#ffffff");
          gradient.addColorStop(0.5, "#f8fafc");
          gradient.addColorStop(1, "#cbd5e1");
        }

        ctx.beginPath();
        ctx.arc(x, y, radius, 0, Math.PI * 2);
        ctx.fillStyle = gradient;
        ctx.fill();

        ctx.shadowColor = "transparent";
        ctx.lineWidth = 1;
        ctx.strokeStyle = player === BLACK ? "rgba(255,255,255,0.1)" : "rgba(15,23,42,0.16)";
        ctx.stroke();

        if (lastMove) {
          ctx.beginPath();
          ctx.arc(x, y, radius * 0.2, 0, Math.PI * 2);
          ctx.fillStyle = player === BLACK ? "rgba(255,255,255,0.92)" : "rgba(15,23,42,0.92)";
          ctx.fill();
        }

        ctx.restore();
      }

      function drawBoard() {
        const width = canvas.clientWidth;
        const height = canvas.clientHeight;
        if (!width || !height) {
          return;
        }

        ctx.clearRect(0, 0, width, height);

        const backdrop = ctx.createLinearGradient(0, 0, width, height);
        backdrop.addColorStop(0, "#f8d996");
        backdrop.addColorStop(0.55, "#ddb56f");
        backdrop.addColorStop(1, "#c68b44");
        ctx.fillStyle = backdrop;
        ctx.fillRect(0, 0, width, height);

