          ctx.beginPath();
          ctx.moveTo(index, 0);
          ctx.lineTo(index - height, height);
          ctx.lineWidth = 6;
          ctx.strokeStyle = "#6b3f16";
          ctx.stroke();
        }
        ctx.restore();

        const padding = Math.max(38, Math.min(width, height) * 0.1);
        const gridExtent = Math.min(width, height) - padding * 2;
        const cell = gridExtent / (SIZE - 1);
        const left = (width - gridExtent) / 2;
        const top = (height - gridExtent) / 2;
        metrics = { width, height, left, top, cell, gridExtent };

        drawRoundedRect(left - cell * 0.72, top - cell * 0.72, gridExtent + cell * 1.44, gridExtent + cell * 1.44, cell * 0.4);
        ctx.fillStyle = "rgba(255, 248, 220, 0.08)";
        ctx.fill();

        ctx.strokeStyle = "rgba(76, 45, 14, 0.88)";
        ctx.lineWidth = Math.max(1.4, cell * 0.05);
        ctx.lineCap = "round";

        for (let index = 0; index < SIZE; index += 1) {
          const x = left + index * cell;
          const y = top + index * cell;

          ctx.beginPath();
          ctx.moveTo(x, top);
          ctx.lineTo(x, top + gridExtent);
          ctx.stroke();

          ctx.beginPath();
          ctx.moveTo(left, y);
          ctx.lineTo(left + gridExtent, y);
          ctx.stroke();
        }

        ctx.fillStyle = "rgba(76, 45, 14, 0.95)";
        for (const [row, col] of STAR_POINTS) {
          ctx.beginPath();
          ctx.arc(left + col * cell, top + row * cell, Math.max(3, cell * 0.09), 0, Math.PI * 2);
          ctx.fill();
        }

        ctx.save();
        ctx.fillStyle = "rgba(60, 36, 11, 0.86)";
        ctx.font = `${Math.max(12, cell * 0.24)}px Inter, system-ui, sans-serif`;
        ctx.textAlign = "center";
        ctx.textBaseline = "middle";

        for (let index = 0; index < SIZE; index += 1) {
          const x = left + index * cell;
          const y = top + index * cell;
          const labelOffset = cell * 0.64;

          ctx.fillText(COLUMN_LABELS[index], x, top - labelOffset);
          ctx.fillText(COLUMN_LABELS[index], x, top + gridExtent + labelOffset);
          ctx.fillText(String(SIZE - index), left - labelOffset, y);
          ctx.fillText(String(SIZE - index), left + gridExtent + labelOffset, y);
        }
        ctx.restore();

        const stoneRadius = cell * 0.42;
        for (let row = 0; row < SIZE; row += 1) {
          for (let col = 0; col < SIZE; col += 1) {
            const value = state.board[row][col];
            if (value === EMPTY) {
              continue;
            }
            const isLastMove = !!state.lastMove && state.lastMove.row === row && state.lastMove.col === col;
            drawStone(left + col * cell, top + row * cell, stoneRadius, value, 1, isLastMove);
          }
        }

        if (
          hoverPoint &&
          !state.gameOver &&
          state.board[hoverPoint.row][hoverPoint.col] === EMPTY
        ) {
          drawStone(
            left + hoverPoint.col * cell,
            top + hoverPoint.row * cell,
            stoneRadius,
            state.currentPlayer,
            0.42,
            false
          );
        }
      }

      function render() {
        updateStatus();
        drawBoard();
      }

      function resizeCanvas() {
        const rect = boardWrap.getBoundingClientRect();
        if (!rect.width || !rect.height) {
          return;
        }

        const dpr = window.devicePixelRatio || 1;
        canvas.width = Math.round(rect.width * dpr);
        canvas.height = Math.round(rect.height * dpr);
        ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
        render();
      }

      function nearestIntersection(clientX, clientY) {
        if (!metrics) {
          return null;
        }

        const rect = canvas.getBoundingClientRect();
        const x = clientX - rect.left;
        const y = clientY - rect.top;
        const col = Math.round((x - metrics.left) / metrics.cell);
        const row = Math.round((y - metrics.top) / metrics.cell);

        if (row < 0 || row >= SIZE || col < 0 || col >= SIZE) {
          return null;
        }

        const boardX = metrics.left + col * metrics.cell;
        const boardY = metrics.top + row * metrics.cell;
        const distance = Math.hypot(boardX - x, boardY - y);
        if (distance > metrics.cell * 0.48) {
          return null;
        }

        return { row, col };
      }

      canvas.addEventListener("mousemove", (event) => {
        const point = nearestIntersection(event.clientX, event.clientY);
        const changed =
          (!point && hoverPoint) ||
          (point && (!hoverPoint || point.row !== hoverPoint.row || point.col !== hoverPoint.col));
        hoverPoint = point;
        if (changed) {
          drawBoard();
        }
      });

      canvas.addEventListener("mouseleave", () => {
        if (hoverPoint) {
          hoverPoint = null;
          drawBoard();
        }
      });

      canvas.addEventListener("click", (event) => {
        const point = nearestIntersection(event.clientX, event.clientY);
        if (!point) {
          return;
        }
        attemptPlay(point.row, point.col);
      });

      passBtn.addEventListener("click", passTurn);
      undoBtn.addEventListener("click", undoMove);
      newBtn.addEventListener("click", resetGame);
      window.addEventListener("resize", resizeCanvas);

      if (typeof ResizeObserver !== "undefined") {
        const resizeObserver = new ResizeObserver(resizeCanvas);
        resizeObserver.observe(boardWrap);
      }

      window.goGame = {
        getState: () => ({
          board: cloneBoard(state.board),
          currentPlayer: state.currentPlayer,
          captures: cloneCaptures(state.captures),
          passes: state.passes,
          moveNumber: state.moveNumber,
          gameOver: state.gameOver,
          lastMove: state.lastMove ? { ...state.lastMove } : null,
          lastAction: state.lastAction ? { ...state.lastAction } : null,
          note: state.note,
          historyLength: history.length,
