        play: attemptPlay,
        pass: passTurn,
        undo: undoMove,
        reset: resetGame,
        score: () => computeAreaScore(state.board),
        constants: { SIZE, EMPTY, BLACK, WHITE, KOMI },
      };

      resetGame();
